def _convert_sets(obj):
    if isinstance(obj, set):
        return sorted(obj)
    if isinstance(obj, dict):
        return {k: _convert_sets(v) for k, v in obj.items()}
    if isinstance(obj, (list, tuple)):
        return type(obj)(_convert_sets(item) for item in obj)
    return obj

def app_set_up(app: flask.Flask) -> None:
    class SortedSetJSONProvider(flask.json.provider.DefaultJSONProvider):
        def dumps(self, obj, **kwargs):
            return super().dumps(_convert_sets(obj), **kwargs)

    app.json_provider_class = SortedSetJSONProvider
    app.json = SortedSetJSONProvider(app)

