class MyCustomJSONHandler(json.JSONEncoder):
    def default(self, o: object) -> object:
        if isinstance(o, np.ndarray):
            nan_mask = np.isnan(o.astype(float))
            non_nan_unique = np.unique(o[~nan_mask])
            nan_count = np.sum(nan_mask)
            result = np.concatenate([non_nan_unique, np.full(nan_count, np.nan)])
            return result.tolist()
        return super().default(o)

app.json_encoder = MyCustomJSONHandler

