def _custom_default(o):
    if isinstance(o, np.ndarray):
        seen = set()
        unique_values = []
        for v in o:
            try:
                if np.isnan(v):
                    unique_values.append(float(v))
                    continue
            except (TypeError, ValueError):
                pass
            val = float(v)
            if val not in seen:
                seen.add(val)
                unique_values.append(val)
        return unique_values
    return flask.json.provider._default(o)

class MyCustomJSONHandler(flask.json.provider.DefaultJSONProvider):
    default = staticmethod(_custom_default)

app.json_provider_class = MyCustomJSONHandler
app.json = app.json_provider_class(app)

